SELECT COUNT(1) > 0
FROM hub_channels
WHERE mall_key = #{mallKey}

SELECT id, corp_id, user_id, mall_key, account_name, key, key2, auth_key, mall_id, mall_pw, use_yn, vendor_id
FROM user_malls
WHERE corp_id = #{corpId}
  AND id = #{id}

SELECT id, corp_id, user_id, mall_key, account_name, key, key2, auth_key, mall_id, mall_pw, use_yn, vendor_id
FROM user_malls
WHERE corp_id = #{corpId}
  AND id = #{id}
  AND use_yn = 'Y'

SELECT id, corp_id, user_id, mall_key, account_name, key, key2, auth_key, mall_id, mall_pw, use_yn, vendor_id
FROM user_malls
WHERE corp_id = #{corpId}
  AND mall_key = #{mallKey}
  AND use_yn = 'Y'
ORDER BY id

SELECT id, corp_id, user_id, mall_key, account_name, key, key2, auth_key, mall_id, mall_pw, use_yn, vendor_id
FROM user_malls
WHERE corp_id = #{corpId}
  AND mall_key = #{mallKey}
ORDER BY id
LIMIT 1

mapper.update:
UPDATE user_malls
SET account_name = #{accountName},
    key       = #{key},
    key2      = #{key2},
    auth_key  = #{authKey},
    mall_id   = #{mallId},
    mall_pw   = #{mallPw},
    vendor_id = #{vendorId}
WHERE corp_id = #{corpId}
  AND id = #{id}

